previewCss:
.darma-loader-darma-custom-587 {color: var(--loader-color, #f97316);
  --loader-secondary-color: var(--loader-secondary-color, #facc15);
  --loader-bg: var(--loader-bg, #ffffff);
   width: 40px;
   aspect-ratio: 1.154;
   display: grid;
   background: conic-gradient(from 149deg at top,#0000, #BF1E62 1deg 60deg,#0000 61deg);
   animation: darma-loader-darma-custom-587-l14 2s infinite cubic-bezier(0.5,500,0.5,-500);
   transform-origin: top;
}
.darma-loader-darma-custom-587:before, .darma-loader-darma-custom-587:after  {
  content: "";
   grid-area: 1/1;
   background: conic-gradient(from 149deg at top,#0000, #FFA588 1deg 60deg,#0000 61deg);
   transform-origin: inherit;
   animation: inherit;
}
.darma-loader-darma-custom-587:after  {
  background: conic-gradient(from 149deg at top,#0000, #027B7F 1deg 60deg,#0000 61deg);
   animation-timing-function: cubic-bezier(0.5,800,0.5,-800);
}
@keyframes darma-loader-darma-custom-587-l14 {
  100% {transform: rotate(0.2deg)}
}

